1	/**
2	 * FAM-01 — nested family resolver.
3	 *
4	 * Given a family-authored geometry tree (sweep nodes + nested
5	 * `family_instance_ref` placements) plus a host parameter map and
6	 * a family catalog, walks the tree and produces a Three.js Group
7	 * containing the resolved geometry. Nested-family parameter bindings
8	 * pull their effective values from host params, literals, or
9	 * FAM-04 formulas.
10	 *
11	 * Geometry is emitted in millimetre space — the same convention as
12	 * `meshFromSweep` (FAM-02). Callers scale to scene units.
13	 *
14	 * Cycle detection: BFS up to depth 10. `detectFamilyCycle` is
15	 * intended for save-time validation; the resolver itself also
16	 * throws if it walks past the depth limit, defensively guarding
17	 * against in-memory graphs that bypassed save validation.
18	 */
19	
20	import * as THREE from 'three';
21	import { evaluateFormulaOrThrow } from '../lib/expressionEvaluator';
22	import { meshFromSweep } from './sweepGeometry';
23	import type {
24	  FamilyDefinition,
25	  FamilyGeometryNode,
26	  FamilyInstanceRefNode,
27	  ParameterBinding,
28	  SweepGeometryNode,
29	} from './types';
30	
31	/** Max recursion depth for nested-family expansion. */
32	export const MAX_NESTED_FAMILY_DEPTH = 10;
33	
34	export type HostParams = Record<string, number | boolean | string>;
35	
36	export type FamilyCatalogLookup = Record<string, FamilyDefinition>;
37	
38	/**
39	 * Compute the effective value of a single binding against the host
40	 * parameter map. Throws on missing host param or formula error.
41	 */
42	export function resolveParameterBinding(
43	  binding: ParameterBinding,
44	  hostParams: HostParams,
45	): number | boolean | string {
46	  if (binding.kind === 'literal') return binding.value;
47	  if (binding.kind === 'host_param') {
48	    if (!Object.prototype.hasOwnProperty.call(hostParams, binding.paramName)) {
49	      throw new Error(`host_param '${binding.paramName}' not present on host`);
50	    }
51	    return hostParams[binding.paramName];
52	  }
53	  // formula
54	  const numericParams: Record<string, number | boolean> = {};
55	  for (const [k, v] of Object.entries(hostParams)) {
56	    if (typeof v === 'number' || typeof v === 'boolean') numericParams[k] = v;
57	  }
58	  return evaluateFormulaOrThrow(binding.expression, numericParams);
59	}
60	
61	/**
62	 * Build the parameter map a nested family will be resolved against:
63	 * start from the family's declared defaults, then layer the
64	 * `parameterBindings` resolved against the host's params.
65	 */
66	function buildNestedParamMap(
67	  def: FamilyDefinition,
68	  bindings: Record<string, ParameterBinding>,
69	  hostParams: HostParams,
70	): HostParams {
71	  const out: HostParams = {};
72	  for (const p of def.params) {
73	    const dv = p.default;
74	    if (typeof dv === 'number' || typeof dv === 'boolean' || typeof dv === 'string') {
75	      out[p.key] = dv;
76	    }
77	  }
78	  for (const [paramName, binding] of Object.entries(bindings)) {
79	    out[paramName] = resolveParameterBinding(binding, hostParams);
80	  }
81	  return out;
82	}
83	
84	/**
85	 * Resolve a single geometry node to an Object3D.
86	 *
87	 * Sweep nodes go through FAM-02's `meshFromSweep`. Nested-family
88	 * refs recurse into `resolveNestedFamilyInstance`. Returns null
89	 * for nodes hidden by their `visibilityBinding`.
90	 */
91	function resolveGeometryNode(
92	  node: FamilyGeometryNode,
93	  hostParams: HostParams,
94	  catalog: FamilyCatalogLookup,
95	  depth: number,
96	): THREE.Object3D | null {
97	  if (node.kind === 'sweep') {
98	    return resolveSweepNode(node);
99	  }
100	  if (node.kind === 'family_instance_ref') {
101	    return resolveNestedFamilyInstance(node, hostParams, catalog, depth);
102	  }
103	  return null;
104	}
105	
106	function resolveSweepNode(node: SweepGeometryNode): THREE.Mesh {
107	  const geom = meshFromSweep(node);
108	  return new THREE.Mesh(geom);
109	}
110	
111	/**
112	 * FAM-01 entry point. Walks `node.familyId`'s geometry tree using
113	 * effective parameter values derived from `node.parameterBindings`
114	 * + `hostParams`. Returns a Group positioned/rotated per `node`'s
115	 * placement. Hidden subtrees (per `visibilityBinding`) return an
116	 * empty Group rather than null so callers can still attach them.
117	 */
118	export function resolveNestedFamilyInstance(
119	  node: FamilyInstanceRefNode,
120	  hostParams: HostParams,
121	  catalog: FamilyCatalogLookup,
122	  depth: number = 0,
123	): THREE.Group {
124	  if (depth > MAX_NESTED_FAMILY_DEPTH) {
125	    throw new Error(
126	      `FAM-01: nested family depth ${depth} exceeds MAX_NESTED_FAMILY_DEPTH (${MAX_NESTED_FAMILY_DEPTH}); cycle in family graph?`,
127	    );
128	  }
129	  const def = catalog[node.familyId];
130	  if (!def) {
131	    throw new Error(`FAM-01: family '${node.familyId}' not found in catalog`);
132	  }
133	  const group = new THREE.Group();
134	  group.userData.familyId = node.familyId;
135	
136	  // Visibility short-circuit before we recurse.
137	  if (node.visibilityBinding) {
138	    const v = hostParams[node.visibilityBinding.paramName];
139	    const truthy = Boolean(v);
140	    if (truthy !== node.visibilityBinding.whenTrue) {
141	      group.position.set(node.positionMm.xMm, node.positionMm.yMm, node.positionMm.zMm);
142	      group.rotation.y = (node.rotationDeg * Math.PI) / 180;
143	      return group;
144	    }
145	  }
146	
147	  const nestedParams = buildNestedParamMap(def, node.parameterBindings, hostParams);
148	  const geometry = def.geometry ?? [];
149	  for (const geomNode of geometry) {
150	    const child = resolveGeometryNode(geomNode, nestedParams, catalog, depth + 1);
151	    if (child) group.add(child);
152	  }
153	
154	  group.position.set(node.positionMm.xMm, node.positionMm.yMm, node.positionMm.zMm);
155	  group.rotation.y = (node.rotationDeg * Math.PI) / 180;
156	  return group;
157	}
158	
159	/**
160	 * Resolve a top-level family's geometry given a parameter map.
161	 *
162	 * Useful for both family-thumbnail rendering and KRN-09's
163	 * `family_instance` curtain panel resolution where the host (the
164	 * curtain wall) doesn't itself live in a family-instance ref.
165	 */
