1	import { useMemo, useState, type JSX } from 'react';
2	import { useTranslation } from 'react-i18next';
3	import type { FamilyParamDef, SketchLine, SweepGeometryNode } from '../families/types';
4	import { validateFormula } from '../lib/expressionEvaluator';
5	
6	type Template = 'generic_model' | 'door' | 'window' | 'profile';
7	
8	type RefPlane = {
9	  id: string;
10	  name: string;
11	  isVertical: boolean;
12	  offsetMm: number;
13	  isSymmetryRef: boolean;
14	};
15	
16	type Param = {
17	  key: string;
18	  label: string;
19	  type: FamilyParamDef['type'];
20	  default: unknown;
21	  formula: string;
22	};
23	
24	/**
25	 * Resolve a family parameter for rendering.
26	 *
27	 * `paramOverrides` (used by FAM-09 flex mode) takes priority over the
28	 * authored default. Flex values are *not* persisted on save — exiting
29	 * flex mode discards them, so callers pass `undefined` when flex mode
30	 * is off.
31	 */
32	export function resolveFamilyParamValue(
33	  param: Param,
34	  paramOverrides?: Record<string, unknown>,
35	): unknown {
36	  if (paramOverrides && param.key in paramOverrides) {
37	    const override = paramOverrides[param.key];
38	    if (override !== undefined && override !== '') {
39	      return override;
40	    }
41	  }
42	  return param.default;
43	}
44	
45	type SweepDraft = {
46	  pathLines: SketchLine[];
47	  profile: SketchLine[];
48	  profilePlane: 'normal_to_path_start' | 'work_plane';
49	  /** which sub-step the user is in: drawing the path, or sketching the
50	   *  profile loop. */
51	  step: 'path' | 'profile';
52	};
53	
54	const EMPTY_SWEEP_DRAFT: SweepDraft = {
55	  pathLines: [],
56	  profile: [],
57	  profilePlane: 'normal_to_path_start',
58	  step: 'path',
59	};
60	
61	export function FamilyEditorWorkbench(): JSX.Element {
62	  const { t } = useTranslation();
63	  const [template, setTemplate] = useState<Template>('generic_model');
64	  const [refPlanes, setRefPlanes] = useState<RefPlane[]>([]);
65	  const [params, setParams] = useState<Param[]>([]);
66	  const [flexMode, setFlexMode] = useState(false);
67	  const [flexValues, setFlexValues] = useState<Record<string, unknown>>({});
68	  const [sweeps, setSweeps] = useState<SweepGeometryNode[]>([]);
69	  const [sweepDraft, setSweepDraft] = useState<SweepDraft | null>(null);
70	
71	  function addRefPlane(isVertical: boolean) {
72	    setRefPlanes((prev) => [
73	      ...prev,
74	      {
75	        id: crypto.randomUUID(),
76	        name: 'Ref Plane',
77	        isVertical,
78	        offsetMm: 0,
79	        isSymmetryRef: false,
80	      },
81	    ]);
82	  }
83	
84	  function addParam() {
85	    setParams((prev) => [
86	      ...prev,
87	      {
88	        key: `param_${prev.length + 1}`,
89	        label: '',
90	        type: 'length_mm',
91	        default: 0,
92	        formula: '',
93	      },
94	    ]);
95	  }
96	
97	  function updateParam(index: number, patch: Partial<Param>) {
98	    setParams((prev) => prev.map((p, i) => (i === index ? { ...p, ...patch } : p)));
99	  }
100	
101	  function setFlexValue(key: string, raw: string) {
102	    setFlexValues((prev) => {
103	      if (raw === '') {
104	        const next = { ...prev };
105	        delete next[key];
106	        return next;
107	      }
108	      const numeric = Number(raw);
109	      const value: unknown = Number.isFinite(numeric) ? numeric : raw;
110	      return { ...prev, [key]: value };
111	    });
112	  }
113	
114	  function toggleFlexMode() {
115	    setFlexMode((prev) => {
116	      const next = !prev;
117	      // Exiting flex mode discards flex values; defaults are unchanged.
118	      if (!next) setFlexValues({});
119	      return next;
120	    });
121	  }
122	
123	  function resetFlexValues() {
124	    setFlexValues({});
125	  }
126	
127	  function startSweep() {
128	    setSweepDraft({ ...EMPTY_SWEEP_DRAFT });
129	  }
130	
131	  function appendSweepPathLine(line: SketchLine) {
132	    setSweepDraft((prev) => (prev ? { ...prev, pathLines: [...prev.pathLines, line] } : prev));
133	  }
134	
135	  function appendSweepProfileLine(line: SketchLine) {
136	    setSweepDraft((prev) => (prev ? { ...prev, profile: [...prev.profile, line] } : prev));
137	  }
138	
139	  function advanceSweepToProfile() {
140	    setSweepDraft((prev) => (prev ? { ...prev, step: 'profile' } : prev));
141	  }
142	
143	  function finishSweep() {
144	    setSweepDraft((prev) => {
145	      if (!prev) return prev;
146	      if (prev.pathLines.length < 1 || prev.profile.length < 3) {
147	        // Refuse to finish degenerate sweeps; user has to add geometry first.
148	        return prev;
149	      }
150	      const node: SweepGeometryNode = {
151	        kind: 'sweep',
152	        pathLines: prev.pathLines,
153	        profile: prev.profile,
154	        profilePlane: prev.profilePlane,
155	      };
156	      setSweeps((s) => [...s, node]);
157	      return null;
158	    });
159	  }
160	
161	  function cancelSweep() {
162	    setSweepDraft(null);
163	  }
164	
165	  // Resolved parameter values for the canvas — defaults when flex mode
166	  // is off, defaults-merged-with-flex-overrides when on.
167	  const resolved = useMemo(() => {
168	    const overrides = flexMode ? flexValues : undefined;
169	    const map: Record<string, unknown> = {};
170	    for (const param of params) {
171	      map[param.key] = resolveFamilyParamValue(param, overrides);
172	    }
173	    return map;
174	  }, [params, flexMode, flexValues]);
175	
176	  const templates: { value: Template; label: string }[] = [
177	    { value: 'generic_model', label: t('familyEditor.templateGenericModel') },
178	    { value: 'door', label: t('familyEditor.templateDoor') },
179	    { value: 'window', label: t('familyEditor.templateWindow') },
180	    { value: 'profile', label: t('familyEditor.templateProfile') },
181	  ];
182	
183	  return (
184	    <div className="p-4 space-y-6">
185	      <div className="flex gap-2">
186	        {templates.map(({ value, label }) => (
187	          <button
188	            key={value}
189	            className={
190	              template === value
191	                ? 'bg-primary text-white px-3 py-1 rounded'
