163	  const start = new THREE.Vector3(node.axisStart.xMm, node.axisStart.yMm, node.axisStart.zMm);
164	  const end = new THREE.Vector3(node.axisEnd.xMm, node.axisEnd.yMm, node.axisEnd.zMm);
165	  const axisVec = new THREE.Vector3().subVectors(end, start);
166	  const axisLen = axisVec.length();
