29	    kind: 'sweep',
30	    pathLines: [{ startMm: { xMm: 0, yMm: 0 }, endMm: { xMm: 600, yMm: 0 } }],
31	    profile: rectProfile(50, 50),
32	    profilePlane: 'normal_to_path_start',
33	    visibilityBinding,
34	  };
35	}
36	
37	function meshCount(group: THREE.Group): number {
38	  let n = 0;
39	  group.traverse((c) => {
40	    if (c instanceof THREE.Mesh) n++;
41	  });
42	  return n;
43	}
44	
45	describe('FAM-03 isVisibleByBinding', () => {
46	  it('no binding → always visible', () => {
47	    expect(isVisibleByBinding(undefined, {})).toBe(true);
48	  });
49	
50	  it('binds whenTrue: true', () => {
51	    const b: VisibilityBinding = { paramName: 'hasFrame', whenTrue: true };
52	    expect(isVisibleByBinding(b, { hasFrame: true })).toBe(true);
53	    expect(isVisibleByBinding(b, { hasFrame: false })).toBe(false);
54	  });
55	
56	  it('binds whenTrue: false (hide-when-on)', () => {
57	    const b: VisibilityBinding = { paramName: 'hideMe', whenTrue: false };
58	    expect(isVisibleByBinding(b, { hideMe: true })).toBe(false);
59	    expect(isVisibleByBinding(b, { hideMe: false })).toBe(true);
60	  });
61	
62	  it('missing host param is falsy', () => {
63	    const b: VisibilityBinding = { paramName: 'never', whenTrue: true };
64	    expect(isVisibleByBinding(b, {})).toBe(false);
65	  });
66	
67	  it('coerces non-boolean truthy values', () => {
68	    const b: VisibilityBinding = { paramName: 'count', whenTrue: true };
69	    expect(isVisibleByBinding(b, { count: 1 })).toBe(true);
70	    expect(isVisibleByBinding(b, { count: 0 })).toBe(false);
71	  });
72	});
73	
74	describe('FAM-03 visibility on sweep nodes', () => {
75	  function windowWithFrameToggle(): FamilyDefinition {
76	    return {
77	      id: 'window-with-toggle',
78	      name: 'WindowWithToggle',
79	      discipline: 'window',
80	      params: [
81	        {
82	          key: 'hasFrame',
83	          label: 'Has Frame',
84	          type: 'boolean',
85	          default: false,
86	          instanceOverridable: true,
87	        },
88	      ],
89	      defaultTypes: [],
90	      geometry: [frameSweep({ paramName: 'hasFrame', whenTrue: true })],
91	    };
92	  }
93	
94	  it('hides the bound sweep when host param is false', () => {
95	    const def = windowWithFrameToggle();
96	    const group = resolveFamilyGeometry(def.id, { hasFrame: false }, { [def.id]: def });
97	    expect(meshCount(group)).toBe(0);
98	  });
99	
100	  it('shows the bound sweep when host param is true', () => {
101	    const def = windowWithFrameToggle();
102	    const group = resolveFamilyGeometry(def.id, { hasFrame: true }, { [def.id]: def });
103	    expect(meshCount(group)).toBeGreaterThanOrEqual(1);
104	  });
105	
106	  it('default param value (false) hides the sweep when host params are empty', () => {
107	    const def = windowWithFrameToggle();
108	    const group = resolveFamilyGeometry(def.id, {}, { [def.id]: def });
109	    expect(meshCount(group)).toBe(0);
110	  });
111	
112	  it('mixed sweep nodes — some bound, some unconditional', () => {
113	    const def: FamilyDefinition = {
114	      id: 'mixed',
115	      name: 'Mixed',
116	      discipline: 'window',
117	      params: [
118	        {
119	          key: 'hasFrame',
120	          label: 'Has Frame',
121	          type: 'boolean',
122	          default: false,
123	          instanceOverridable: true,
124	        },
125	      ],
126	      defaultTypes: [],
127	      geometry: [frameSweep(), frameSweep({ paramName: 'hasFrame', whenTrue: true })],
128	    };
129	    const offGroup = resolveFamilyGeometry(def.id, { hasFrame: false }, { [def.id]: def });
130	    expect(meshCount(offGroup)).toBe(1);
131	    const onGroup = resolveFamilyGeometry(def.id, { hasFrame: true }, { [def.id]: def });
132	    expect(meshCount(onGroup)).toBe(2);
133	  });
134	});

